<template>
    <div class="container-fluid d-flex flex-column align-items-center pb-5 p-0" style="font-family: 'Inter';">
<!-- HERO -->
        <div class="jumbotron jumbotron-fluid py-3 w-100">
            <div class="container py-5">
                <h2 class="display-5 fw-bold">Pronto per una Revisione?</h2>
                <p class="lead">Contattaci per ricevere un’analisi gratuita del tuo caso archiviato</p>
            </div>
        </div>
<!-- FEATURES -->
        <section class="py-5 bg-light w-100">
            <div class="container">
                <h2 class="text-center mb-5">Perché scegliere la nostra Revisione</h2>
                <div class="row g-4">
                    <div class="col-md-4 text-center" v-for="(feature, index) in features" :key="index">
                        <div class="mb-3">
                             <img :src="feature.icon" :alt="feature.title" style="width: 4rem;">
                        </div>
                        <h5 style="color: #004f8e;">{{ feature.title }}</h5>
                        <p>{{ feature.desc }}</p>
                    </div>
                </div>
            </div>
        </section>
<!-- TIMELINE -->
        <section class="py-5 text-start ms-4 ms-lg-0">
            <h2 class="h3 mb-4">Come funziona</h2>
            <ul class="timeline">
                <li class="timeline-item mb-4" v-for="(step, index) in steps" :key="index">
                    <h5>{{ step.title }}</h5>
                    <p class="text-muted text-wrap">{{ step.desc }}</p>
                </li>
            </ul>
        </section>
        <div class="card border-0 bg-light col-md-10 col-lg-6">
            <div class="card-body py-4">
                <form ref="cases" class="card-body needs-validation" novalidate @submit.prevent="sendCase" enctype="multipart/form-data">
                    <div class="d-flex flex-wrap mb-3 gap-4">
<!-- NOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="nome" class="form-label"><small>Nome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.name}" id="nome" name="nome" v-model="cases.name" required>
                            <div class="invalid-feedback">
                                {{ errors.name }}
                            </div>
                        </div>
<!-- COGNOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cognome" class="form-label"><small>Cognome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.lastname}" id="cognome" name="cognome" v-model="cases.lastname" required>
                            <div class="invalid-feedback">
                                {{ errors.lastname }}
                            </div>
                        </div>
<!-- CELLULARE -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cellulare" class="form-label me-1"><small>Cellulare</small> <span class="form-text">(Opzionale)</span></label>
                            <input type="tel" class="form-control rounded-2 border border-1" id="cellulare" name="cellulare" v-model="cases.phone" @input="cases.phone = cases.phone.replace(/\D/g, '')">
                        </div>
                    </div>
<!-- EMAIL -->
                    <div class="col-12 col-md-12 col-lg-6 mb-3 text-start">
                        <label for="email" class="form-label"><small>Email</small> <span class="text-danger">*</span></label>
                        <input type="email" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.email}" id="email" name="email" v-model="cases.email" required>
                        <div class="invalid-feedback">
                            {{ errors.email }}
                        </div>
                    </div>
<!-- ALLEGA FILE -->
                    <div class="mb-3 text-start">
                        <label for="file" class="form-label text-danger fst-italic"><small>Impossibile allegare file</small></label>
                        <input type="file" class="form-control rounded-2 border border-1" id="file" name="file" ref="file" disabled>
                        <div class="invalid-feedback">
                            {{ errors.file }}
                        </div>
                    </div>
<!-- MESSAGGIO -->
                    <div class="mb-3 text-start">
                        <label for="messaggio" class="form-label"><small>Descrizione Caso</small></label>
                        <textarea class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.message}" id="messaggio" name="messaggio" rows="10" v-model="cases.message" required></textarea>
                        <div class="invalid-feedback">
                            {{ errors.messaggio }}
                        </div>
                    </div>
<!-- PRIVACY POLICY -->
                    <div class="form-check mb-3 text-start">
                        <input class="form-check-input" id="privacy" type="checkbox" :class="{'is-invalid': errors.privacy}" v-model="cases.privacy">
                        <label for="privacy" class="form-check-label text-dark"><small>Acconsento al trattamento dei miei dati personali, come descritto nella Privacy Policy, esclusivamente per ricevere una risposta al mio messaggio.</small> <span class="text-danger">*</span></label>
                        <div class="invalid-feedback">
                            {{ errors.privacy }}
                        </div>
                    </div>
<!-- PULSANTE DI INVIO -->
                    <div class="d-flex justify-content-center justify-content-lg-end pt-1">
                        <button class="btn btn-block btn-primary px-3 py-2 rounded-1 border-0" type="submit" style="font-family: 'Inter';" @click="showAlert">Richiedi Revisione</button>
                    </div>
                </form>
            </div>
        </div>
    </div>
</template>

<script>
import emailjs from '@emailjs/browser'; 
import Swal from 'sweetalert2';

export default {
    name: 'CaseForm',
    metaInfo() {
        const path = this.$route.path;
        const canonicalURL = `https://amglablecce.it${path}`;
        return {
            title: 'Revisione casi',
            titleTemplate: '%s | AMG Lab',
            link: [
                { rel: 'canonical', href: canonicalURL }
            ],
            meta: [
                { name: 'description', content: 'Hai un caso di infortunistica stradale archiviato? Affidati al nostro servizio di revisione per una nuova valutazione professionale.' }
            ]
        };
    },
    data() {
        return {
            features: [
                { icon: require('../assets/historical.png'), title: 'Analisi Storica', desc: 'Rivalutiamo ogni parametro delle tue perizie passate' },
                { icon: require('../assets/connection.png'), title: 'Forensic Technology', desc: 'Verifica e validazione dei dati del sinistro' },
                { icon: require('../assets/bar-chart.png'), title: 'Report Avanzati', desc: 'Grafici e statistiche per ogni fase di revisione' }
            ],
            steps: [
                { title: 'Invio Dati',        desc: 'Invia i file delle perizie e la documentazione associata' },
                { title: 'Analisi Preliminare', desc: 'Verifica rapida di coerenza dati e gap informativi' },
                { title: 'Ricalcolo Dinamico', desc: 'Ricostruzione cinematica con gli strumenti più avanzati' },
                { title: 'Consegna Report',   desc: 'Ricevi un report dettagliato pronto per il CTU/CTP' }
            ],
            cases: {
                nome: '',
                cognome: '',
                cellulare: '',
                email: '',
                messaggio: '',
            },
            errors: {}
        }
    },
    methods: {
        sendCase(event) {
            if (this.showAlert()) {
                event.preventDefault();
                emailjs.sendForm('service_z746n4j', 'template_rnslkem', this.$refs.cases, 'zv6jTrcK-qf47MfQb')
                .then(() => {
                    Swal.fire({ icon : 'success', title : 'Successo!', text : 'La tua richiesta di revisione è stata inoltrata. Ti ricontatteremo al più presto.', confirmButtonColor : '#3085d6'});
                    this.resetForm();
                })
                .catch(() => {
                    Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'C\'è stato un problema durante l\'invio della richiesta', confirmButtonColor : '#3085d6'});
                });
            } else {
                Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'Controlla i campi inseriti', confirmButtonColor : '#3085d6'});
            }
        },
        showAlert() {
            this.errors = {};
            let valid = true;

            if (!this.cases.name) {
                this.errors.name = 'Non hai inserito il tuo nome';
                valid = false;
            }
            if (!this.cases.lastname) {
                this.errors.lastname = 'Non hai inserito il tuo cognome';
                valid = false;
            }
            if (!this.cases.email) {
                this.errors.email = 'Non hai inserito la tua email';
                valid = false;
            } else if (!this.cases.email.includes('@')) {
                this.errors.email = 'Non hai inserito la @ alla tua email';
                valid = false;
            } else if (!this.cases.email.includes('.')) {
                this.errors.email = 'La tua email deve contenere un punto (.)';
                valid = false;
            }
            if (!this.cases.message) {
                this.errors.message = 'Descrivi il caso archiviato';
                valid = false;
            }
            if (!this.cases.privacy) {
                this.errors.privacy = 'Devi accettare la privacy policy';
                valid = false;
            }

            return valid;
        },
        resetForm() {
            this.cases = { name : '', lastname : '', email : '', phone : '', message : '', privacy: false };
            this.errors = {};
            this.$refs.cases.reset();
        },
        closeModal() {
            if (this._bsModal) {
                this._bsModal.hide();
            }
        }
    },
    mounted() {
        // chiave specifica per PageContacts
        const key = 'fileAlertShown_CaseForm';
        if (!sessionStorage.getItem(key)) {
            Swal.fire({
                title: 'Avviso Importante',
                icon: 'info',
                html: `
                <p>Al momento non è possibile allegare file. Stiamo lavorando per ripristinare la funzionalità il prima possibile.</p>
                <p>Se desideri comunque inviarci documenti, scrivici a
                    <a href="mailto:amglab.info@gmail.com">amglab.info@gmail.com</a>.
                </p>`,
                confirmButtonText: 'Ho capito',
                confirmButtonColor: '#3085d6',  // verde rassicurante
                allowOutsideClick: false,
                allowEscapeKey: false,
                backdrop: true
            });
            sessionStorage.setItem(key, 'true');
        }
    }
};
</script>

