<script>
import emailjs from '@emailjs/browser'; 
import Swal from 'sweetalert2';

export default {
    name: 'PageHome',
    metaInfo() {
        const path = this.$route.path;
        const canonicalURL = `https://amglablecce.it${path}`;
        return {
            title: 'AMG Lab',
            link: [
                { rel: 'canonical', href: canonicalURL }
            ],
            meta: [
                { name: 'description', content: 'AMG Lab si occupa di infortunistica stradale: ricostruzione incidenti, rilievi 3D, perizie tecnico-forense per CTU/CTP.' }
            ]
        };
    },
    data() {
        return {
            choiceList: [
                {
                    title: "Competenza specialistica",
                    text: "Il nostro team vanta anni di esperienza in ambito Tecnico-Forense: ogni analisi è condotta con rigore metodologico e conoscenze aggiornate.",
                    img: require("../assets/car-insurance.gif")
                },
                {
                    title: "Report chiari e dettagliati",
                    text: "Adottiamo un approccio collaborativo, affiancando il consulente CTU/CTP con documentazione tecnica completa, comprensiva di grafici, foto e video editing per supportare in modo chiaro e incisivo le sue tesi in ambito legale e amministrativo. I nostri report strutturati rendono i dati immediatamente comprensibili e facilmente difendibili in ogni contesto.",
                    img: require("../assets/document.gif")
                },
                {
                    title: "Supporto personalizzato",
                    text: "Seguiamo da vicino ogni progetto, offrendo consulenze e assistenza continuativa: dal primo sopralluogo fino alle fasi di sviluppo e validazione, adattando gli interventi alle tue esigenze.",
                    img: require("../assets/handshake.gif")
                },
                {
                    title: "Tempi rapidi e costi trasparenti",
                    text: "Sfruttando il nostro modello di smart working, operiamo con tempistiche definite e preventivi dettagliati. Ricevi il tuo elaborato puntualmente, senza imprevisti, e gestisci il budget con la massima tranquillità.",
                    img: require("../assets/fast-forward.gif")
                }
            ],
            cardList: [
                {
                    img: "",
                    alt: ""
                },
            ],
            form: {
                nome: '',
                cognome: '',
                cellulare: '',
                email: '',
                messaggio: '',
            },
            errors: {}
        }
    },
    mounted() {
        const vid = this.$refs.myVideo;
        vid.onloadedmetadata = () => {
            vid.play();
            vid.pause();
        };
    },
    methods: {
        onVisible(visible) {
            if (visible) this.isVisible = true;
        },
        sendMail(event) {
            if (this.showAlert()) {
                event.preventDefault();
                emailjs.sendForm('service_z746n4j', 'template_rnslkem', this.$refs.form, 'zv6jTrcK-qf47MfQb')
                .then(() => {
                    Swal.fire({ icon : 'success', title : 'Successo!', text : 'Messaggio inviato con successo', confirmButtonColor : '#3085d6'});
                    this.resetForm();
                })
                .catch(() => {
                    Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'C\'è stato un problema durante l\'invio del messaggio', confirmButtonColor : '#3085d6'});
                });
            } else {
                Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'Controlla i campi inseriti', confirmButtonColor : '#3085d6'});
            }
        },
        showAlert() {
            this.errors = {};
            let valid = true;

            if (!this.form.name) {
                this.errors.name = 'Non hai inserito il tuo nome';
                valid = false;
            }
            if (!this.form.lastname) {
                this.errors.lastname = 'Non hai inserito il tuo cognome';
                valid = false;
            }
            if (!this.form.email) {
                this.errors.email = 'Non hai inserito la tua email';
                valid = false;
            } else if (!this.form.email.includes('@')) {
                this.errors.email = 'Non hai inserito la @ alla tua email';
                valid = false;
            } else if (!this.form.email.includes('.')) {
                this.errors.email = 'La tua email deve contenere un punto (.)';
                valid = false;
            }
            if (!this.form.message) {
                this.errors.message = 'Non hai inserito il tuo messaggio';
                valid = false;
            }

            return valid;
        },
        resetForm() {
            this.form = { name : '', lastname : '', email : '', phone : '', message : ''};
            this.errors = {};
            this.$refs.form.reset();
        },
        scrollToContact() {
            const section = document.getElementById('contattaci');
            if (section) {
                section.scrollIntoView({ behavior: 'smooth' });
            }
        }
    }
}
</script>

