<template>
    <div class="container-fluid d-flex flex-column align-items-center pb-5 p-0" style="font-family: 'Inter'; background-color: #f2f6f8;">
<!-- HERO -->
        <div class="jumbotron jumbotron-fluid py-3 w-100">
            <div class="container py-5">
                <h2 class="display-5 fw-bold">Prenota la Tua Consulenza Tecnica</h2>
                <p class="lead">Supporto specializzato per CTU/CTP in ogni fase del procedimento</p>
            </div>
        </div>
<!-- FEATURES -->
        <section class="py-5 bg-white w-100">
            <div class="container">
                <h2 class="text-center mb-5">I Nostri Servizi di Consulenza</h2>
                <div class="row g-4">
                    <!-- DA CAMBIARE (col- ecc.) SE IMPLEMENTIAMO ALTRE FEATURES -->
                    <div class="col-md-12 col-lg-12 text-center" v-for="(feature, index) in features" :key="index">
                        <div class="mb-3">
                             <img :src="feature.icon" :alt="feature.title" style="width: 4rem;">
                        </div>
                        <h5 style="color: #004f8e;">{{ feature.title }}</h5>
                        <p>{{ feature.desc }}</p>
                    </div>
                </div>
            </div>
        </section>
<!-- TIMELINE -->
        <section class="py-5 text-start">
            <h2 class="h3 mb-4">Come funziona</h2>
            <ul class="timeline">
                <li class="timeline-item mb-4" v-for="(step, index) in steps" :key="index">
                    <h5>{{ step.title }}</h5>
                    <p class="text-muted">{{ step.desc }}</p>
                </li>
            </ul>
        </section>
        <div class="card border-0 col-md-10 col-lg-6">
            <div class="card-body py-4">
                <form ref="consult" class="card-body needs-validation" novalidate @submit.prevent="sendConsultancy" enctype="multipart/form-data">
                    <div class="d-flex flex-wrap mb-3 gap-4">
<!-- NOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="nome" class="form-label"><small>Nome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.name}" id="nome" name="nome" v-model="consult.name" required>
                            <div class="invalid-feedback">
                                {{ errors.name }}
                            </div>
                        </div>
<!-- COGNOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cognome" class="form-label"><small>Cognome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.lastname}" id="cognome" name="cognome" v-model="consult.lastname" required>
                            <div class="invalid-feedback">
                                {{ errors.lastname }}
                            </div>
                        </div>
<!-- CELLULARE -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cellulare" class="form-label me-1"><small>Cellulare</small> <span class="form-text">(Opzionale)</span></label>
                            <input type="tel" class="form-control rounded-2 border border-1" id="cellulare" name="cellulare" v-model="consult.phone" @input="consult.phone = consult.phone.replace(/\D/g, '')">
                        </div>
                    </div>
<!-- EMAIL -->
                    <div class="col-12 col-md-12 col-lg-6 mb-3 text-start">
                        <label for="email" class="form-label"><small>Email</small> <span class="text-danger">*</span></label>
                        <input type="email" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.email}" id="email" name="email" v-model="consult.email" required>
                        <div class="invalid-feedback">
                            {{ errors.email }}
                        </div>
                    </div>
<!-- ALLEGA FILE -->
                    <div class="mb-3 text-start">
                        <label for="file" class="form-label text-danger fst-italic"><small>Impossibile allegare file</small></label>
                        <input type="file" class="form-control rounded-2 border border-1" id="file" name="file" ref="file" disabled>
                        <div class="invalid-feedback">
                            {{ errors.file }}
                        </div>
                    </div>
<!-- MESSAGGIO -->
                    <div class="mb-3 text-start">
                        <label for="messaggio" class="form-label"><small>Messaggio</small></label>
                        <textarea class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.message}" id="messaggio" name="messaggio" rows="10" v-model="consult.message" required></textarea>
                        <div class="invalid-feedback">
                            {{ errors.message }}
                        </div>
                    </div>
<!-- PRIVACY POLICY -->
                    <div class="form-check mb-3 text-start">
                        <input class="form-check-input" id="privacy" type="checkbox" :class="{'is-invalid': errors.privacy}" v-model="consult.privacy">
                        <label for="privacy" class="form-check-label text-dark"><small>Acconsento al trattamento dei miei dati personali, come descritto nella Privacy Policy, esclusivamente per ricevere una risposta al mio messaggio.</small> <span class="text-danger">*</span></label>
                        <div class="invalid-feedback">
                            {{ errors.privacy }}
                        </div>
                    </div>
<!-- PULSANTE DI INVIO -->
                    <div class="d-flex justify-content-center justify-content-lg-end pt-1">
                        <button class="btn btn-block btn-primary px-3 py-2 rounded-1 border-0" type="submit" style="font-family: 'Inter';" @click="showAlert">Prenota Consulenza</button>
                    </div>
                </form>
            </div>
        </div>
        
    </div>
</template>

<script>
import emailjs from '@emailjs/browser'; 
import Swal from 'sweetalert2';

export default {
    name: 'CaseForm',
    metaInfo() {
        const path = this.$route.path;
        const canonicalURL = `https://amglablecce.it${path}`;
        return {
            title: 'Consulenze',
            titleTemplate: '%s | AMG Lab',
            link: [
                { rel: 'canonical', href: canonicalURL }
            ],
            meta: [
                { name: 'description', content: 'Offriamo consulenze per aiutarti a raggiungere i tuoi obiettivi. Scopri come il nostro team può supportarti nel tuo percorso.' }
            ]
        };
    },
    data() {
        return {
            features: [
                { icon: require('../assets/group.png'), title: 'Supporto CTU/CTP', desc: 'Affiancamento tecnico in tutte le fasi' },
                // { icon: require('../assets/judgment.png'), title: 'Pareri Legali', desc: 'Consulenze integrate con l’avvocato.' },
                // { icon: require('../assets/quality.png'), title: 'Assistenza Udienza', desc: 'Presenza del consulente in tribunale.' }
            ],
            steps: [
                { title: 'Richiesta Consulenza', desc: 'Invia i dettagli del caso tramite il form' },
                { title: 'Briefing Tecnico', desc: 'Incontro preliminare per definire obiettivi' },
                { title: 'Elaborazione Parere', desc: 'Redazione del documento tecnico-legale' },
                { title: 'Assistenza Finale', desc: 'Supporto in dibattimento e revisioni' }
            ],
            consult: {
                nome: '',
                cognome: '',
                cellulare: '',
                email: '',
                messaggio: '',
                privacy: false
            },
            errors: {}
        }
    },
    methods: {
        sendConsultancy(event) {
            if (this.showAlert()) {
                event.preventDefault();
                emailjs.sendForm('service_z746n4j', 'template_rnslkem', this.$refs.consult, 'zv6jTrcK-qf47MfQb')
                .then(() => {
                    Swal.fire({ icon : 'success', title : 'Successo!', text : 'Richiesta inviata! Ti contatteremo al più presto per fissare l’appuntamento.', confirmButtonColor : '#3085d6'});
                    this.resetForm();
                })
                .catch(() => {
                    Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'C\'è stato un problema durante l\'invio della richiesta', confirmButtonColor : '#3085d6'});
                });
            } else {
                Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'Controlla i campi inseriti', confirmButtonColor : '#3085d6'});
            }
        },
        showAlert() {
            this.errors = {};
            let valid = true;

            if (!this.consult.name) {
                this.errors.name = 'Non hai inserito il tuo nome';
                valid = false;
            }
            if (!this.consult.lastname) {
                this.errors.lastname = 'Non hai inserito il tuo cognome';
                valid = false;
            }
            if (!this.consult.email) {
                this.errors.email = 'Non hai inserito la tua email';
                valid = false;
            } else if (!this.consult.email.includes('@')) {
                this.errors.email = 'Non hai inserito la @ alla tua email';
                valid = false;
            } else if (!this.consult.email.includes('.')) {
                this.errors.email = 'La tua email deve contenere un punto (.)';
                valid = false;
            }
            if (!this.consult.message) {
                this.errors.message = 'Non hai inserito il tuo messaggio';
                valid = false;
            }
            if (!this.consult.privacy) {
                this.errors.privacy = 'Devi accettare la privacy policy';
                valid = false;
            }

            return valid;
        },
        resetForm() {
            this.consult = { name : '', lastname : '', email : '', phone : '', message : '', privacy: false};
            this.errors = {};
            this.$refs.consult.reset();
        }
    },
    mounted() {
        // chiave specifica per PageContacts
        const key = 'fileAlertShown_ConsultancyForm';
        if (!sessionStorage.getItem(key)) {
            Swal.fire({
                title: 'Avviso Importante',
                icon: 'info',
                html: `
                <p>Al momento non è possibile allegare file. Stiamo lavorando per ripristinare la funzionalità il prima possibile.</p>
                <p>Se desideri comunque inviarci documenti, scrivici a
                    <a href="mailto:amglab.info@gmail.com">amglab.info@gmail.com</a>.
                </p>`,
                confirmButtonText: 'Ho capito',
                confirmButtonColor: '#3085d6',  // verde rassicurante
                allowOutsideClick: false,
                allowEscapeKey: false,
                backdrop: true
            });
            sessionStorage.setItem(key, 'true');
        }
    }
};
</script>

<style>
.timeline {
    border-left: 2px solid hsl(0, 0%, 85%);
    position: relative;
    list-style: none;
}

.timeline .timeline-item {
    position: relative;
}

.timeline .timeline-item:after {
    position: absolute;
    display: block;
    top: 0;
}

.timeline .timeline-item:after {
    background-color: #2E8B57;
    left: -38px;
    border-radius: 50%;
    height: 11px;
    width: 11px;
    content: "";
}
</style>