<template>
    <div class="container-fluid d-flex flex-column align-items-center pb-5 p-0" style="font-family: 'Inter'; background-color: #f5f5ff;">
<!-- HERO -->
        <div class="jumbotron jumbotron-fluid py-3 w-100">
            <div class="container py-5">
                <h2 class="display-5 fw-bold" style="color: #2E8B57">Richiedi un Preventivo Personalizzato</h2>
                <p class="lead">Precisione e rapidità per CTU/CTP nell’infortunistica stradale</p>
            </div>
        </div>
<!-- FEATURES -->
        <section class="py-5 w-100" style="background-color: #e7eefe;">
            <div class="container">
                <h2 class="text-center mb-5">I Vantaggi dei Nostri Preventivi</h2>
                <div class="row g-4">
                    <div class="col-md-4 text-center" v-for="(feature, index) in features" :key="index">
                        <div class="mb-3">
                             <img :src="feature.icon" :alt="feature.title" style="width: 4rem;">
                        </div>
                        <h5 style="color: #004f8e;">{{ feature.title }}</h5>
                        <p>{{ feature.desc }}</p>
                    </div>
                </div>
            </div>
        </section>
<!-- TIMELINE -->
        <section class="py-5 text-start">
            <h2 class="h3 mb-4">Come funziona</h2>
            <ul class="timeline">
                <li class="timeline-item mb-4" v-for="(step, index) in steps" :key="index">
                    <h5>{{ step.title }}</h5>
                    <p class="text-muted">{{ step.desc }}</p>
                </li>
            </ul>
        </section>
        <div class="card border-0 col-12 col-md-10 col-lg-8">
            <div class="card-body py-4">
                <form ref="quotes" class="card-body needs-validation" novalidate @submit.prevent="sendQuote" enctype="multipart/form-data">
<!-- BUDGET -->
                    <div class="mb-5 text-start">
                        <legend class="lead mb-5 p-0 text-center">Seleziona il servizio che ti serve e scopri subito il costo per interventi tecnici infortunistica stradale</legend>
                        <div class="pricing_design d-flex flex-wrap justify-content-center align-items-start gap-2">
                            <div v-for="opt in budgetOption" :key="opt.value" class="form-check form-check-inline single-pricing position-relative d-flex flex-column justify-content-between align-items-center p-0 px-4 mx-auto" style="width: 22rem; height: 44rem;">
                                <span class="position-absolute top-0 px-4 py-1 border border-0 rounded-bottom text-white fw-semibold" style="background: #407faf; font-size: 1rem;">{{ opt.title }}</span>
                                <div class="pt-5 mt-2 text-start">
                                    <label class="form-check-label mt-5 mb-4 text-dark fs-5" :for="opt.value">{{ opt.label }}</label>
                                    <div v-for="(optList, index) in opt.list" :key="index" class="d-flex align-items-center gap-3 border-top py-3">
                                        <span style='font-size: 20px; color: cadetblue'>&#10004;</span>
                                        <p class="m-0 text-start text-secondary" :for="opt.value">{{ optList.item }}</p>
                                    </div>
                                </div>
                                <input class="form-check-input m-0 mb-4" :class="{'is-invalid': errors.budget}" :value="opt.value" :id="opt.value" type="radio" name="budget" v-model="quotes.budget" required>
                            </div>
                        </div>
                        <small class="text-danger">
                            {{ errors.budget }}
                        </small>
                    </div>
                    <div class="d-flex flex-wrap mb-3 gap-4">
<!-- NOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="nome" class="form-label"><small>Nome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.name}" id="nome" name="nome" v-model="quotes.name" required>
                            <div class="invalid-feedback">
                                {{ errors.name }}
                            </div>
                        </div>
<!-- COGNOME -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cognome" class="form-label"><small>Cognome</small> <span class="text-danger">*</span></label>
                            <input type="text" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.lastname}" id="cognome" name="cognome" v-model="quotes.lastname" required>
                            <div class="invalid-feedback">
                                {{ errors.lastname }}
                            </div>
                        </div>
<!-- CELLULARE -->
                        <div class="col-12 col-md-12 col-lg-3 text-start">
                            <label for="cellulare" class="form-label me-1"><small>Cellulare</small> <span class="form-text">(Opzionale)</span></label>
                            <input type="tel" class="form-control rounded-2 border border-1" id="cellulare" name="cellulare" v-model="quotes.phone" @input="quotes.phone = quotes.phone.replace(/\D/g, '')">
                        </div>
                    </div>
<!-- EMAIL -->
                    <div class="col-12 col-md-12 col-lg-4 mb-3 text-start">
                        <label for="email" class="form-label"><small>Email</small> <span class="text-danger">*</span></label>
                        <input type="email" class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.email}" id="email" name="email" v-model="quotes.email" required>
                        <div class="invalid-feedback">
                            {{ errors.email }}
                        </div>
                    </div>
<!-- MESSAGGIO -->
                    <div class="mb-3 text-start">
                        <label for="messaggio" class="form-label"><small>Come possiamo aiutarti?</small></label>
                        <textarea class="form-control rounded-2 border border-1" :class="{'is-invalid': errors.message}" id="messaggio" name="messaggio" rows="10" v-model="quotes.message" required></textarea>
                        <div class="invalid-feedback">
                            {{ errors.message }}
                        </div>
                    </div>
<!-- PRIVACY POLICY -->
                    <div class="form-check mb-3 text-start">
                        <input class="form-check-input" id="privacy" type="checkbox" :class="{'is-invalid': errors.privacy}" v-model="quotes.privacy">
                        <label for="privacy" class="form-check-label text-dark"><small>Acconsento al trattamento dei miei dati personali al fine di ricevere una risposta al mio messaggio, come indicato nella Privacy Policy.</small> <span class="text-danger">*</span></label>
                        <div class="invalid-feedback">
                            {{ errors.privacy }}
                        </div>
                    </div>
<!-- PULSANTE DI INVIO -->
                    <div class="d-flex justify-content-center justify-content-lg-end pt-1">
                        <button class="btn btn-block btn-success px-3 py-2 rounded-1 border-0" type="submit" style="font-family: 'Inter';" @click="showAlert">Richiedi Preventivo</button>
                    </div>
                </form>
            </div>
        </div>
    </div>
</template>

<script>
import emailjs from '@emailjs/browser'; 
import Swal from 'sweetalert2';

export default {
    name: 'PageContacts',
    metaInfo() {
        const path = this.$route.path;
        const canonicalURL = `https://amglablecce.it${path}`;
        return {
            title: 'Preventivi',
            titleTemplate: '%s | AMG Lab',
            link: [
                { rel: 'canonical', href: canonicalURL }
            ],
            meta: [
                { name: 'description', content: 'Richiedi un preventivo personalizzato in pochi clic. Scopri i nostri servizi e ottieni un\'offerta su misura per le tue esigenze.' }
            ]
        };
    },
    data() {
        return {
            features: [
                { icon: require('../assets/historical.png'),   title: 'Rapidità',       desc: 'Preventivo entro 24/48 ore lavorative' },
                { icon: require('../assets/historical.png'), title: 'Trasparenza',   desc: 'Costi sempre chiari e dettagliati' },
                { icon: require('../assets/historical.png'), title: 'Precisione',     desc: 'Analisi tecnica con margine d’errore minimo' }
            ],
            steps: [
                { title: 'Richiesta',        desc: 'Compila il form con dettagli e documenti' },
                { title: 'Analisi Interna',  desc: 'Valutazione delle specifiche del caso' },
                { title: 'Elaborazione',     desc: 'Calcolo puntuale di tempi e costi' },
                { title: 'Invio Preventivo', desc: 'Ricevi l’offerta completa via email' }
            ],
            quotes: {
                nome: '',
                cognome: '',
                cellulare: '',
                email: '',
                budget: '',
                messaggio: '',
                privacy: false
            },
            errors: {},
            budgetOption: [
                {
                    value: 'base',
                    title: 'Base',
                    label: 'Analisi del caso',
                    list: [
                        { item: 'Ricostruzione 2D/3D della posizione di quiete dei veicoli coinvolti e punto d\'urto' },
                        { item: 'Report fotografico in formato A3' },
                        { item: 'Tempi di consegna 5-7 giorni lavorativi' }
                    ]
                },
                {
                    value: 'medio',
                    title: 'Medio',
                    label: 'Analisi del caso',
                    list: [
                        { item: 'Ricostruzione 2D delle fasi del sinistro' },
                        { item: 'Ricostruzione 3D statica della sequenza del sinistro' },
                        { item: 'Composizione grafica in formato A3' },
                        { item: 'Tempi di consegna 7-10 giorni lavorativi' }
                    ]
                },
                {
                    value: 'avanzato',
                    title: 'Avanzato',
                    label: 'Analisi del caso',
                    list: [
                        { item: 'Ricostruzione 2D dettagliata dello stato dei luoghi' },
                        { item: 'Ricostruzione 3D con simulazione dinamica del sinistro' },
                        { item: 'Restituzione delle clip con la dinamica del sinistro' },
                        { item: 'Tavola tecnica in formato compatibile con plotter' },
                        { item: 'Tempi di consegna 15-20 giorni lavorativi' }
                    ]
                },
            ]
        }
    },
    methods: {
        sendQuote(event) {
            if (this.showAlert()) {
                event.preventDefault();
                emailjs.sendForm('service_z746n4j', 'template_uvu7b4u', this.$refs.quotes, 'zv6jTrcK-qf47MfQb')
                .then(() => {                                                                                        
                    Swal.fire({ icon : 'success', title : 'Successo!', text : 'Preventivo inviato! Ti risponderemo entro 24/48 ore.', confirmButtonColor : '#3085d6'});
                    this.resetForm();
                })
                .catch(() => {
                    Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'C\'è stato un problema durante l\'invio del preventivo', confirmButtonColor : '#3085d6'});
                });
            } else {
                Swal.fire({ icon : 'error', title : 'Si è verificato un errore', text : 'Controlla i campi inseriti', confirmButtonColor : '#3085d6'});
            }
        },
        showAlert() {
            this.errors = {};
            let valid = true;

            if (!this.quotes.name) {
                this.errors.name = 'Non hai inserito il tuo nome';
                valid = false;
            }
            if (!this.quotes.lastname) {
                this.errors.lastname = 'Non hai inserito il tuo cognome';
                valid = false;
            }
            if (!this.quotes.email) {
                this.errors.email = 'Non hai inserito la tua email';
                valid = false;
            } else if (!this.quotes.email.includes('@')) {
                this.errors.email = 'Non hai inserito la @ alla tua email';
                valid = false;
            } else if (!this.quotes.email.includes('.')) {
                this.errors.email = 'La tua email deve contenere un punto (.)';
                valid = false;
            }
            if (!this.quotes.budget) {
                this.errors.budget = 'Seleziona un budget',
                valid = false;
            }
            if (!this.quotes.message) {
                this.errors.message = 'Non hai inserito il tuo messaggio';
                valid = false;
            }
            if (!this.quotes.privacy) {
                this.errors.privacy = 'Devi accettare la privacy policy';
                valid = false;
            }

            return valid;
        },
        resetForm() {
            this.quotes = { name : '', lastname : '', email : '', phone : '', budget: '', message : '', privacy: false};
            this.errors = {};
            this.$refs.quotes.reset();
        }
    }
};
</script>

<style>
.timeline {
    border-left: 2px solid hsl(0, 0%, 85%);
    position: relative;
    list-style: none;
}

.timeline .timeline-item {
    position: relative;
}

.timeline .timeline-item:after {
    position: absolute;
    display: block;
    top: 0;
}

.timeline .timeline-item:after {
    background-color: #2e8b57;
    left: -38px;
    border-radius: 50%;
    height: 11px;
    width: 11px;
    content: "";
}

.pricing_design{
    position: relative;
    margin: 0px 15px;
}

.single-pricing{
    background: #fff;
    padding: 40px 35px;
    position: relative;
    border-radius: 10px;
    overflow: hidden;
    box-shadow: 0 10px 30px -10px rgba(0,64,128,.2);
}

.single-pricing:before{
    position: absolute;
    content: "";
    top: 10px;
    right: -35px;
    width: 100px;
    height: 100px;
    background: #0cc652;
    opacity: 0.2;
    border-radius: 8px;
    transform: rotate(45deg);
}

.single-pricing:after{
    position: absolute;
    content: "";
    top: -10px;
    right: -35px;
    width: 100px;
    height: 100px;
    background: #0cc652;
    opacity: 0.2;
    border-radius: 8px;
    transform: rotate(45deg);
}
</style>