<template>
    <div class="col-12 col-sm-6 col-md-4 col-lg-3">
        <div class="card rounded-0 border-0 h-100 shadow-sm">
            <!-- <div class="d-block" style="object-fit: cover;">
                <video class="w-100" :src="item.clips" preload="metadata">
                    <source v-if="item.clips" :src="item.clips" type="video/mp4">
                </video>
            </div> -->
            <div class="ratio ratio-4x3" @click="openModal" style="cursor: pointer;">
                <img v-if="item.photos" :src="item.photos" class="card-img-top img-fluid rounded-0" :alt="item.title || 'Media photo'" style="cursor: zoom-in;" loading="lazy" />
            </div>
            <!-- <div class="card-body d-flex flex-column">
                <h5 class="card-title">{{ item.title }}</h5>
            </div> -->
        </div>
<!-- Modal personalizzato -->
        <div v-if="isModalOpen" class="modal fade d-block" :class="{ show: isModalOpen }" tabindex="-1" @click.self="closeModal">
            <div class="modal-dialog modal-dialog-centered modal-dialog-scrollable modal-lg">
                <div class="modal-content rounded-0">
                    <div class="modal-header">
                        <button type="button" class="btn-close" @click="closeModal"></button>
                    </div>
                    <div class="modal-body p-0" @wheel.prevent="onWheel" @mousedown.prevent="startDrag" @mousemove.prevent="onDrag" @mouseup.prevent="endDrag" @mouseleave.prevent="endDrag">
                        <img :src="item.photos" class="img-fluid" :alt="item.title || 'Media photo full'" :style="{transform: `translate(${offsetX}px, ${offsetY}px) scale(${zoomLevel})`, transformOrigin: 'center center'}" />
                    </div>
<!-- Slider zoom -->
                    <div class="slider-overlay d-flex gap-2 mx-auto p-3 fw-semibold fs-5" style="width: 80%;" @click.stop>
                        <span>-</span>
                        <input type="range" v-model.number="zoomLevel" @input="setZoom(zoomLevel)" min="1" max="3" step="0.1" />
                        <span>+</span>
                    </div>
<!-- Controlli zoom -->
                    <!-- <div class="zoom-controls p-2">
                        <button class="border-0 m-1 rounded-1 fw-bold" style="width: 40px; height: 40px" @click.stop="zoomIn">+</button>
                        <button class="border-0 m-1 rounded-1 fw-bold" style="width: 40px; height: 40px" @click.stop="zoomOut">-</button>
                    </div> -->
                </div>
            </div>
        </div>
    </div>
</template>

<script>
export default {
    name: 'CardImage',
    props: {
        item: {
            type: Object,
            required: true
        }
    },
    data() {
        return {
            isModalOpen: false,
            zoomLevel: 1,
            offsetX: 0,
            offsetY: 0,
            dragStartX: 0,
            dragStartY: 0,
            isDragging: false
        }
    },
    methods: {
        openModal() {
            this.zoomLevel = 1;
            this.offsetX = 0;
            this.offsetY = 0;
            this.isModalOpen = true;
            document.body.classList.add('modal-open');
        },
        closeModal() {
            this.isModalOpen = false;
            document.body.class.remove('modal-open');
        },
        zoomIn() {
            this.setZoom(this.zoomLevel + 0.2);
        },
        zoomOut() {
            this.setZoom(this.zoomLevel - 0.2);
        },
        onWheel(event) {
            event.deltaY < 0 ? this.zoomIn() : this.zoomOut();
        },
        setZoom(newZoom) {
            const minZoom = 1;
            const maxZoom = 3;
            this.zoomLevel = Math.min(Math.max(newZoom, minZoom), maxZoom);
            this.clampOffsets();
        },
        startDrag(event) {
            if (this.zoomLevel <= 1) return;
            this.isDragging = true;
            this.dragStartX = event.clientX - this.offsetX;
            this.dragStartY = event.clientY - this.offsetY;
        },
        onDrag(event) {
            if (!this.isDragging) return;
            this.offsetX = event.clientX - this.dragStartX;
            this.offsetY = event.clientY - this.dragStartY;
            this.clampOffsets();
        },
        endDrag() { 
            this.isDragging = false;
        },
        clampOffsets() {
            const container = this.$el.querySelector('.modal-body');
            if (!container) return;
            const rect = container.getBoundingClientRect();
            const imgWidth = rect.width * this.zoomLevel;
            const imgHeight = rect.height * this.zoomLevel;
            const maxX = (imgWidth - rect.width) / 2;
            const maxY = (imgHeight - rect.height) / 2;
            this.offsetX = Math.min(Math.max(this.offsetX, -maxX), maxX);
            this.offsetY = Math.min(Math.max(this.offsetY, -maxY), maxY);
        }
    }
}
</script>

<style lang="scss" scoped>
.card-img-top {
    object-fit: cover;
}

.modal {
    background-color: rgba(0, 0, 0, 0.5);
}

.modal.fade:not(.show) {
    display: none;
}

.modal-body {
    object-fit: contain;
    cursor: grab;
}

.img-fluid {
    transition: transform .2s ease;
}

.slider-overlay input[type="range"] {
    width: 80%;
}

// .modal-open {
//     overflow: hidden;
// }
</style>